import{_ as i,c as e,o as t,ah as l}from"./chunks/framework.Cnj7lwEt.js";const p=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/动画工具/Lottie iOS-动画工具.md","filePath":"github汇总/动画工具/Lottie iOS-动画工具.md"}'),r={name:"github汇总/动画工具/Lottie iOS-动画工具.md"};function o(h,a,s,n,d,c){return t(),e("div",null,a[0]||(a[0]=[l('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>Lottie iOS</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>Airbnb</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>动画工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>传统移动应用中，设计师制作好复杂动画后，工程师需要手动用代码重写动画效果，耗时且难以保证效果一致性；同时不同平台需要分别实现，增加开发成本和维护难度。</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>跨平台支持iOS、macOS、tvOS和visionOS</li><li>原生渲染After Effects导出的bodymovin JSON格式矢量动画</li><li>支持多种安装方式：Swift Package Manager、CocoaPods、Carthage</li><li>动画控制功能：播放、缩放、循环、加速、减速、反向播放</li><li>交互式 scrub 拖动进度条控制</li><li>支持播放动画片段</li><li>运行时动态修改动画属性（颜色、位置等关键帧值）</li><li>隐私友好，不收集任何数据</li><li>提供隐私清单支持</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>设计师和工程师协作更高效，设计师做的动画可直接在应用中使用</li><li>基于JSON的动画文件体积小但复杂度高</li><li>提供专门优化的小体积版本(lottie-spm)供快速下载</li><li>支持Xcode签名验证，安全性有保障</li><li>完整的单元测试和快照测试体系</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/airbnb/lottie-ios" target="_blank" rel="noreferrer">https://github.com/airbnb/lottie-ios</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于iOS、macOS、tvOS或visionOS开发者，需要在应用中集成矢量动画的场景。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li>Xcode版本：需要支持当前Apple官方App Store提交要求的最低Swift/Xcode版本</li><li>项目类型：iOS、macOS、tvOS或visionOS应用项目</li><li>依赖管理：可选择Swift Package Manager、CocoaPods或Carthage任一方式</li></ol><h2 id="主路径-swift-package-manager安装-推荐" tabindex="-1">主路径：Swift Package Manager安装（推荐） <a class="header-anchor" href="#主路径-swift-package-manager安装-推荐" aria-label="Permalink to “主路径：Swift Package Manager安装（推荐）”">​</a></h2><h3 id="步骤1-添加包依赖" tabindex="-1">步骤1：添加包依赖 <a class="header-anchor" href="#步骤1-添加包依赖" aria-label="Permalink to “步骤1：添加包依赖”">​</a></h3><p>步骤目标：在Xcode项目中添加Lottie依赖 执行位置：Xcode IDE 完整命令或操作： 在Xcode中，选择「File」→「Add Packages...」 输入URL：<a href="https://github.com/airbnb/lottie-spm.git" target="_blank" rel="noreferrer">https://github.com/airbnb/lottie-spm.git</a> 成功标志：Xcode成功加载包信息并显示版本选择 失败处理：检查网络连接，确认URL正确，或尝试使用主仓库地址</p><h3 id="步骤2-选择版本" tabindex="-1">步骤2：选择版本 <a class="header-anchor" href="#步骤2-选择版本" aria-label="Permalink to “步骤2：选择版本”">​</a></h3><p>步骤目标：选择适合项目的Lottie版本 执行位置：Xcode包添加界面 完整命令或操作：选择从4.5.2版本开始的合适版本 成功标志：版本选择完成，点击「Add Package」 失败处理：查看Swift Package Index了解支持的Swift版本</p><h3 id="步骤3-导入使用" tabindex="-1">步骤3：导入使用 <a class="header-anchor" href="#步骤3-导入使用" aria-label="Permalink to “步骤3：导入使用”">​</a></h3><p>步骤目标：在代码中导入并使用Lottie 执行位置：项目源代码文件 完整命令或操作：</p><div class="language-swift"><button title="Copy Code" class="copy"></button><span class="lang">swift</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Lottie</span></span></code></pre></div><p>成功标志：编译无错误，可正常使用Lottie相关API 失败处理：确认包已正确添加到目标中，检查Build Settings</p><h2 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h2><h3 id="备选路径1-cocoapods安装" tabindex="-1">备选路径1：CocoaPods安装 <a class="header-anchor" href="#备选路径1-cocoapods安装" aria-label="Permalink to “备选路径1：CocoaPods安装”">​</a></h3><p>步骤目标：使用CocoaPods安装Lottie 执行位置：项目根目录终端 完整命令或操作：</p><ol><li>在Podfile中添加：<code>pod &#39;lottie-ios&#39;</code></li><li>运行：<code>pod install</code> 成功标志：pod install成功执行，生成.xcworkspace文件 失败处理：更新CocoaPods版本，检查Ruby环境</li></ol><h3 id="备选路径2-carthage安装" tabindex="-1">备选路径2：Carthage安装 <a class="header-anchor" href="#备选路径2-carthage安装" aria-label="Permalink to “备选路径2：Carthage安装”">​</a></h3><p>步骤目标：使用Carthage安装Lottie 执行位置：项目根目录终端 完整命令或操作：</p><ol><li>在Cartfile中添加：<code>github &quot;airbnb/lottie-ios&quot; &quot;master&quot;</code></li><li>运行：<code>carthage update</code></li><li>在应用目标「General」选项卡的「Linked Frameworks and Libraries」部分，拖放Carthage/Build/iOS目录中的lottie-ios.framework 成功标志：framework成功添加到项目中 失败处理：检查Carthage版本，确认Xcode命令行工具已安装</li></ol><h3 id="备选路径3-直接包含源码" tabindex="-1">备选路径3：直接包含源码 <a class="header-anchor" href="#备选路径3-直接包含源码" aria-label="Permalink to “备选路径3：直接包含源码”">​</a></h3><p>步骤目标：直接克隆仓库并包含项目 执行位置：项目目录 完整命令或操作： 克隆仓库：<code>git clone https://github.com/airbnb/lottie-ios.git</code> 将Lottie.xcodeproj包含到项目中 成功标志：项目可正常编译 失败处理：确认项目结构正确，检查依赖关系</p><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><ol><li>在代码中导入Lottie模块，编译无错误</li><li>尝试创建一个Lottie动画视图并加载示例JSON动画</li><li>运行应用，确认动画可以正常播放</li></ol><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>现象 -&gt; 编译错误，找不到Lottie模块</strong> 可能原因 -&gt; 包未正确添加到目标中 解决步骤 -&gt; 检查Build Phases中的Link Binary With Libraries，确认Lottie已添加</p></li><li><p><strong>现象 -&gt; Swift Package Manager下载缓慢</strong> 可能原因 -&gt; 主仓库体积较大(300+MB) 解决步骤 -&gt; 改用lottie-spm仓库(小于500KB)，地址：<a href="https://github.com/airbnb/lottie-spm.git" target="_blank" rel="noreferrer">https://github.com/airbnb/lottie-spm.git</a></p></li><li><p><strong>现象 -&gt; 动画无法加载或显示空白</strong> 可能原因 -&gt; JSON文件格式不正确或路径错误 解决步骤 -&gt; 确认JSON文件是有效的bodymovin格式，检查文件路径和Bundle资源配置</p></li></ol>',43)]))}const g=i(r,[["render",o]]);export{p as __pageData,g as default};
